import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"CuratedPython","description":"Credit https://curatedpython.com/p/yacht-yet-cantoolz-cantoolz/index.html","frontmatter":{"description":"Credit https://curatedpython.com/p/yacht-yet-cantoolz-cantoolz/index.html"},"headers":[],"relativePath":"obd2/car-hacking/curatedpython.md","filePath":"obd2/car-hacking/curatedpython.md"}'),s={name:"obd2/car-hacking/curatedpython.md"};function l(r,e,n,h,d,p){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="curatedpython" tabindex="-1">CuratedPython <a class="header-anchor" href="#curatedpython" aria-label="Permalink to &quot;CuratedPython&quot;">​</a></h1><h2 id="cantoolz" tabindex="-1">CANToolz <a class="header-anchor" href="#cantoolz" aria-label="Permalink to &quot;CANToolz&quot;">​</a></h2><h3 id="a-k-a" tabindex="-1">a.k.a. <a class="header-anchor" href="#a-k-a" aria-label="Permalink to &quot;a.k.a.&quot;">​</a></h3><p>. It provides multiple modules that can be chained using CANToolz&#39;s <code>pipe</code> system and used by security researchers, automotive/OEM security testers in black-box analysis.</p><p>CANToolz can be used for ECU discovery, MitM testing, fuzzing, brute-forcing, scanning or R&amp;D, testing and validation. More can easily be implemented with a new module.</p><p>Many tools are already available for CAN analysis, with Charlie Miller and Chris Valasek tools, UDS/CAN tools by Craig Smith and many more . Each of them is cool and useful but it can be tedious when trying to use several of them at once. One may need to have a working setup for each them, modify/hack some of their source code, implement new features to be specific to one&#39;s project, etc.</p><p>The CANToolz framework is an attempt to unify most (if not all) the tricks, tools and others things that one would need to do CAN analysis in one unique place. A single installation process and many modules already available. The more people we bring in, the more useful it will become! No stunt-hack to bring the people, just a practical and useful tool for anyone to use. Implementing new modules is fairly easy and can be merged with the framework is the community finds it useful.</p><p>The framework is really module-oriented, where one could use one, two, a couple of them as part of a testing process or to create more sophisticated simulation scenarios to work with CAN bus.</p><blockquote><p>&quot;I don&#39;t get why everyone releases new &quot;car hacking tools&quot; all the time. @nudehaberdasher and I released ours in 2013 and they work fine.&quot; - (c) Charlie Miller (@0xcharlie)</p></blockquote><blockquote><p>&quot;Looking for our car hacking tools / data / scripts? <a href="http://illmatics.com/content.zip" target="_blank" rel="noreferrer">http://illmatics.com/content.zip</a>&quot; - (c) Chris Valasek @nudehaberdasher</p></blockquote><p>More details and use-case examples available on:</p><ul><li>Author&#39;s blog</li><li>CANToolz&#39;s Telegram group.</li><li>CANToolz&#39;s Wiki.</li></ul><h3 id="supported-hardware" tabindex="-1">Supported hardware <a class="header-anchor" href="#supported-hardware" aria-label="Permalink to &quot;Supported hardware&quot;">​</a></h3><p>CANToolz supports the following hardware to communicate with CAN bus:</p><ol><li>USBtin</li><li>CANBus Triple</li><li>Seeed CAN-BUS Shield 1.2</li></ol><p>More hardware could be supported. Feel free to open a request.</p><h3 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h3><p>Using manual installation (installing missing dependencies as well):</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> setup</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> install</span></span></code></pre></div><p>The installation process will create a <code>cantoolz</code> alias command in your bin/ folder. To start <code>cantoolz</code>, simply run:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cantoolz</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> w</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> examples</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">can_sniff</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">py</span></span></code></pre></div><p>Then go to CANToolz&#39;s web interface at <a href="http://localhost:4444" target="_blank" rel="noreferrer">http://localhost:4444</a></p><p>Help is available with:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cantoolz</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">h</span></span></code></pre></div><p>_Last stable release for Python 2.7: <a href="https://github.com/eik00d/CANToolz/tree/Python%5C_2.7%5C_last%5C_release_" target="_blank" rel="noreferrer">https://github.com/eik00d/CANToolz/tree/Python\\_2.7\\_last\\_release_</a></p><h3 id="vircar-starting" tabindex="-1">VIRCar starting: <a class="header-anchor" href="#vircar-starting" aria-label="Permalink to &quot;VIRCar starting:&quot;">​</a></h3><p>VIRCar is a Virtual Car simulated using CANToolz&#39;s features and modules:</p><ol><li>Run VIRCar <code>cantoolz -g w -p 5555 -c examples/car_config.py</code></li><li>Go to <a href="http://localhost:5555/index.html" target="_blank" rel="noreferrer">http://localhost:5555/index.html</a> and press <code>START</code></li><li>Go to <a href="http://localhost:5555/vircar.html" target="_blank" rel="noreferrer">http://localhost:5555/vircar.html</a> to see your own Virtual Car!</li></ol><p>Now, to start hacking your new virtual car, you can load the existing configuration example:</p><ol><li>Run CANToolz <code>cantoolz -g w -c examples/car_hacker.py</code> to load and start the hacking session</li><li>Go to <a href="http://localhost:4444/index.html" target="_blank" rel="noreferrer">http://localhost:4444/index.html</a> and you are now connected to VIRCar with <code>car_hacker</code> configuration, using TCP2CAN for I/O hardware and connected to VIRCar&#39;s OBD2 and CABIN buses, and ready to start playing around</li></ol><h3 id="available-modules" tabindex="-1">Available modules <a class="header-anchor" href="#available-modules" aria-label="Permalink to &quot;Available modules&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>Description</th></tr></thead><tbody><tr><td>hw_CANBusTriple</td><td>IO module for CANBus Triple HW</td></tr><tr><td>hw_USBtin</td><td>IO module for USBtin</td></tr><tr><td>hw_CANSocket</td><td>IO module for CANSocket (Linux only)</td></tr><tr><td>hw_TCP2CAN</td><td>client/server IO component for tunnelinc raw CAN traffic over TCP</td></tr><tr><td>hw_CAN232</td><td>IO module for LAWICEL (USB to Serial) CAN devices (e.g. SeeedStudio CAN bus shield)</td></tr><tr><td>firewall</td><td>module for blocking CAN message by ID</td></tr><tr><td>fuzz</td><td>Simple &#39;Proxy&#39; fuzzer (1 byte) Can be combined with ping/replay</td></tr><tr><td>mod_printMessage</td><td>printing CAN messages</td></tr><tr><td>analyze</td><td>CAN messages statistic (with .csv file output) / Analysis option (c analyze a) will try to find UDS/ISO TP messages</td></tr><tr><td>ping</td><td>generating CAN messages with chosen IDs (ECU/Service discovery)</td></tr><tr><td>replay</td><td>save and replay packets</td></tr></tbody></table><p>We are working on supporting other types of I/O hardware and modules. Please join us! With your help, we can create modules that can be useful for all of us!</p><h3 id="usage-examples" tabindex="-1">Usage Examples <a class="header-anchor" href="#usage-examples" aria-label="Permalink to &quot;Usage Examples&quot;">​</a></h3><ul><li>CAN Switch filter scanner</li><li>Checking which CAN frames can be passed from diagnostic interface to HU and back</li><li>MITM with firewall (ECU ID detection)</li><li>Checking what packets are responsible for chosen &quot;action&quot;</li><li>Replay discovery</li><li>Checking what packets are responsible for chosen &quot;action&quot;</li><li>Ping discovery (with ISO TP and UDS support)</li><li>UDS detection, etc.</li></ul><p>And many other possible scenarios. Some of them can be found in the example folder of this repository.</p><p>Just use modules as &quot;needed&quot;:</p><ul><li>Example with DIFF mode, to find door unlock commands.</li></ul><h3 id="sniffing-and-uds-detection-example" tabindex="-1">Sniffing and UDS detection example <a class="header-anchor" href="#sniffing-and-uds-detection-example" aria-label="Permalink to &quot;Sniffing and UDS detection example&quot;">​</a></h3><h3 id="use-it-as-is" tabindex="-1">Use it as-is <a class="header-anchor" href="#use-it-as-is" aria-label="Permalink to &quot;Use it as-is&quot;">​</a></h3><p>As one can expect from hacker tools, CANToolz is very early-uber-alpha. It needs to be tested more; the code can be ugly some times; bugs remain to be found. We are working on that, step by step 😉</p><p>Therefore, use it as-is!</p><h3 id="a-question-comment" tabindex="-1">A question/comment? <a class="header-anchor" href="#a-question-comment" aria-label="Permalink to &quot;A question/comment?&quot;">​</a></h3><ul><li>IRC: #cantoolz @ freenode.net</li><li>Telegram: <a href="https://t.me/CANToolz" target="_blank" rel="noreferrer">https://t.me/CANToolz</a></li></ul><h3 id="with-best-regards" tabindex="-1">With best regards <a class="header-anchor" href="#with-best-regards" aria-label="Permalink to &quot;With best regards&quot;">​</a></h3><ul><li>Alexey Sintsov (@asintsov) / [email protected] -- Creator of CANtoolz</li></ul>',46)])])}const m=a(s,[["render",l]]);export{u as __pageData,m as default};
